<?php namespace App\Repositories\Hr;use App\Repositories\BaseRepository;use App\Models\Hr\Employee;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class EmployeeRepository extends BaseRepository{    public function __construct(Employee $model)    {        $this->model = $model;        parent::__construct($model);    }    public function getByDepartment(int $departmentId): Collection    {        return $this->findByField('department_id', $departmentId);    }    public function getByDesignation(int $designationId): Collection    {        return $this->findByField('designation_id', $designationId);    }    public function searchEmployees(string $keyword): Collection    {        return $this->query()->where(function ($q) use ($keyword) {                $q->where('first_name', 'like', "%{$keyword}%")->orWhere('last_name', 'like', "%{$keyword}%")->orWhere('employee_no', 'like', "%{$keyword}%")->orWhere('email', 'like', "%{$keyword}%")->orWhere('phone', 'like', "%{$keyword}%")->orWhereRaw("CONCAT(first_name, ' ', last_name) LIKE ?", ["%{$keyword}%"]);            })->get();    }    public function getActiveEmployees(): Collection    {        return $this->query()->where('status', 'active')->get();    }    public function findByEmployeeNo(string $employeeNo): ?Employee    {        return $this->query()->where('employee_no', $employeeNo)->first();    }    public function findByEmail(string $email): ?Employee    {        return $this->query()->where('email', $email)->first();    }    public function getByEmploymentType(string $type): Collection    {        return $this->findByField('employment_type', $type);    }    public function getByWorkShift(string $shift): Collection    {        return $this->findByField('work_shift', $shift);    }    public function getByJoiningDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('date_of_joining', [$startDate, $endDate])->get();    }    public function getEmployeesByDepartmentWithUsers(int $departmentId): Collection    {        return $this->query()->where('department_id', $departmentId)->with('user')->get();    }    public function countByDepartment(): Collection    {        return $this->query()->selectRaw('department_id, COUNT(*) as total')->groupBy('department_id')->get();    }    public function countByGender(): Collection    {        return $this->query()->selectRaw('gender, COUNT(*) as total')->groupBy('gender')->get();    }    public function getBirthdayThisMonth(): Collection    {        return $this->query()->whereMonth('date_of_birth', now()->month)->where('status', 'active')->get();    }    public function getWorkAnniversaryThisMonth(): Collection    {        return $this->query()->whereMonth('date_of_joining', now()->month)->where('status', 'active')->get();    }}